import{_ as t,o as a,c as n,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Improved SAN Management UI","description":"","frontmatter":{"title":"Improved SAN Management UI","slug":"improved-san-management-ui"},"headers":[],"relativePath":"account-hub/improved-san-management-ui.md","filePath":"account-hub/improved-san-management-ui.md"}'),i={name:"account-hub/improved-san-management-ui.md"};function r(s,e,c,d,u,l){return a(),n("div",null,[...e[0]||(e[0]=[o('<p>We&#39;ve updated the Partner Management page in Branch - specifically for self-attributing networks (SANs). Learn more here! 🍎</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The UI for Branch&#39;s SAN Partner Management has been improved to include new functionality and better experience. Previously, managing multiple ad accounts across ad partners was difficult and caused attribution errors or pause in data. With an updated UI, you can now easily do the following:</p><ul><li><strong>Alert Banner</strong>: Refined the text to clearly define issue scenarios to help avoid confusion between cost data ingestion and data attribution issues.</li><li><strong>Partner Disablement</strong>: Emphasized the button visually and added a pop-up reminder for the potential impact of disablement after customers click on it.</li><li><strong>Connection Management</strong>: Added ‘Reauthenticate’ and ‘Disconnect’ (hidden in the 3 dots) buttons under the authenticated ad account Connection, with separate pop-up impact reminders after customers click on them.</li><li><strong>Ad Account Management</strong>: Provided a ‘Manage Account’ button to allow customers to select or remove authenticated ad accounts conveniently.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Looking to learn more about SANs and respective guides for each network? View our guide <a href="./self-attributing-networks-sans.html">here</a>.</p></div>',5)])])}const h=t(i,[["render",r]]);export{p as __pageData,h as default};
